import React, { useState } from 'react';
import { View, Button, Alert } from 'react-native';
import { InAppPurchase, useIAP } from 'react-native-iap';
import { PaymentRequest } from 'react-native-payments';

const productIds = ['com.example.product1', 'com.example.product2'];

const PaymentModule = () => {
  const [productList, setProductList] = useState([]);
  const { connected, getProducts, requestPurchase } = useIAP();

  const initIAP = async () => {
    try {
      const products = await getProducts(productIds);
      setProductList(products);
    } catch (err) {
      console.warn(err);
    }
  };

  const handlePurchase = async (productId) => {
    try {
      await requestPurchase(productId);
      Alert.alert('Purchase Successful');
    } catch (err) {
      Alert.alert('Purchase Failed', err.message);
    }
  };

  const handleDigitalWalletPayment = async () => {
    const paymentRequest = new PaymentRequest({
      countryCode: 'US',
      currencyCode: 'USD',
      total: {
        label: 'Your Total',
        amount: '10.00',
      },
      supportedNetworks: ['visa', 'mastercard'],
      merchantCapabilities: ['supports3DS'],
    });

    try {
      const paymentResponse = await paymentRequest.show();
      paymentResponse.complete('success');
      Alert.alert('Payment Successful');
    } catch (err) {
      Alert.alert('Payment Failed', err.message);
    }
  };

  React.useEffect(() => {
    if (connected) {
      initIAP();
    }
  }, [connected]);

  return (
    <View>
      {productList.map((product) => (
        <Button
          key={product.productId}
          title={`Buy ${product.title}`}
          onPress={() => handlePurchase(product.productId)}
        />
      ))}
      <Button title="Pay with Digital Wallet" onPress={handleDigitalWalletPayment} />
    </View>
  );
};

export default PaymentModule;